/** Tra nội dung điền tay của một quẻ (theo kingWen). undefined nếu chưa soạn. */
export function hexagramExtraByKingWen(kingWen: number): HexagramExtra | undefined {
  return HEXAGRAM_CONTENT[kingWen];
}

/** Đã có đủ hào từ 6 hào cho quẻ này chưa (badge tiến độ). */
export function hasLineTexts(kingWen: number): boolean {
  return HEXAGRAM_CONTENT[kingWen]?.lines?.length === 6;
}
